INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019cd9eb-d853-7183-88d3-c7e853762c39', 'Gemini 2.5 Flash Image is Google''s native image generation model, optimized for speed, flexibility, and contextual understanding. Text input and output is priced the same as 2.5 Flash.', '2026-03-10 22:43:58.163079+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019cd9eb-d855-7208-acd9-8349c7128389', 'Gemini 2.5 Flash Lite is a lightweight version of Gemini 2.5 Flash optimized for speed and efficiency.', '2026-03-10 22:43:58.165113+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019cd9eb-d856-7ff8-8869-f7736c0e88e0', 'Gemini 2.5 Flash is a language model that can be used to generate text, images, and audio. Pricing shown is for thinking mode.', '2026-03-10 22:43:58.166987+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019cd9eb-d859-728f-b35a-2a033916d158', 'Gemini 2.5 Pro is Google''s most advanced language model with enhanced reasoning and multimodal capabilities. Pricing shown is for context windows ≤200k tokens.', '2026-03-10 22:43:58.169146+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019cd9eb-d85a-7f38-85b7-2f7fdd7dd0c1', 'Gemini 3 Pro Image Preview is Google''s native image generation model, optimized for speed, flexibility, and contextual understanding. Text input and output is priced the same as Gemini 3 Pro.', '2026-03-10 22:43:58.170945+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019cd9eb-d85c-7c1c-bc5a-8c3396484664', 'Gemini 3 Pro Preview is Google''s most advanced language model. Pricing shown is for prompts ≤200k tokens. Separate higher tier for prompts >200k (input $4 / output $18 / cache $0.40).', '2026-03-10 22:43:58.172748+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
